class SecurePaymentHttpClient {
  final PaymentConfig config;
  final PaymentLogger logger;
  final http.Client _client;

  SecurePaymentHttpClient({
    required this.config,
    required this.logger,
    http.Client? client,
  }) : _client = client ?? http.Client();

  Future<Map<String, dynamic>> postJson(
    String path, {
    required Map<String, dynamic> body,
    String? bearerToken,
    Map<String, String>? headers,
  }) async {
    final uri = config.backendBaseUrl.resolve(path);
    final payload = jsonEncode(body);
    final requestHeaders = <String, String>{
      HttpHeaders.contentTypeHeader: 'application/json',
      HttpHeaders.acceptHeader: 'application/json',
      'X-Platform': Platform.isIOS ? 'ios' : 'android',
      'X-Request-Signature': _requestSignature(payload),
      if (bearerToken != null) HttpHeaders.authorizationHeader: 'Bearer $bearerToken',
      ...?headers,
    };

    logger.log('POST $uri', body);

    final response = await _client
        .post(uri, headers: requestHeaders, body: payload)
        .timeout(config.networkTimeout);

    logger.log('RESPONSE ${response.statusCode}', response.body);

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        'http_${response.statusCode}',
        'Payment backend request failed',
        response.body,
      );
    }

    final decoded = jsonDecode(response.body);
    if (decoded is! Map<String, dynamic>) {
      throw const PaymentException('invalid_response', 'Invalid backend response');
    }
    return decoded;
  }

  String _requestSignature(String payload) {
    final key = utf8.encode(config.publishableKey);
    final bytes = utf8.encode(payload);
    return Hmac(sha256, key).convert(bytes).toString();
  }

  void dispose() => _client.close();
}

