class WalletBridge {
  static const MethodChannel _channel = MethodChannel('payment_module/wallets');
  final PaymentLogger logger;

  const WalletBridge(this.logger);

  Future<bool> isWalletAvailable(WalletType type) async {
    final available = await _channel.invokeMethod<bool>(
          'isWalletAvailable',
          {'walletType': describeEnum(type)},
        ) ??
        false;
    logger.log('Wallet availability ${describeEnum(type)}', available);
    return available;
  }

  Future<String> presentWallet(WalletPaymentRequest request) async {
    final token = await _channel.invokeMethod<String>(
      'presentWallet',
      {
        'walletType': describeEnum(request.walletType),
        'currencyCode': request.currencyCode,
        'countryCode': request.countryCode,
        'amount': request.amount,
        'label': request.label,
        'merchantIdentifier': request.orderId,
        'metadata': request.metadata ?? <String, dynamic>{},
      },
    );

    if (token == null || token.isEmpty) {
      throw const PaymentException('wallet_cancelled', 'Wallet authorization cancelled');
    }
    return token;
  }
}

class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentGatewayService gatewayService;
  final PaymentLogger logger;

  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final StreamController<PaymentResult> _purchaseResults = StreamController.broadcast();

  InAppPurchaseService({
    required this.gatewayService,
    required this.logger,
  });

  Stream<PaymentResult> get purchaseResults => _purchaseResults.stream;

  Future<void> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) {
      throw const PaymentException('iap_unavailable', 'In-app purchases are not available');
    }

    _subscription ??= _iap.purchaseStream.listen(
      _onPurchaseUpdate,
      onError: (Object error, StackTrace stackTrace) {
        logger.log('IAP stream error', error);
        _purchaseResults.add(
          PaymentResult(
            status: PaymentStatus.failed,
            transactionId: '',
            message: error.toString(),
          ),
        );
      },
    );
  }

  Future<PurchaseCatalog> queryProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);
    if (response.error != null) {
      throw PaymentException(
        response.error!.code,
        response.error!.message,
        response.error,
      );
    }
    return PurchaseCatalog(
      products: response.productDetails,
      notFoundIds: response.notFoundIDs,
    );
  }

  Future<void> buyConsumable(ProductDetails product) async {
    final param = PurchaseParam(productDetails: product);
    final ok = await _iap.buyConsumable(purchaseParam: param, autoConsume: true);
    if (!ok) {
      throw const PaymentException('purchase_start_failed', 'Could not start consumable purchase');
    }
  }

  Future<void> buyNonConsumable(ProductDetails product) async {
    final param = PurchaseParam(productDetails: product);
    final ok = await _iap.buyNonConsumable(purchaseParam: param);
    if (!ok) {
      throw const PaymentException('purchase_start_failed', 'Could not start non-consumable purchase');
    }
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  Future<void> _onPurchaseUpdate(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      try {
        switch (purchase.status) {
          case PurchaseStatus.pending:
            _purchaseResults.add(
              PaymentResult(
                status: PaymentStatus.pending,
                transactionId: purchase.purchaseID ?? '',
                message: 'Purchase pending',
              ),
            );
            break;
          case PurchaseStatus.purchased:
          case PurchaseStatus.restored:
            final verification = await gatewayService.verifyStorePurchase(
              source: Platform.isIOS ? 'app_store' : 'play_store',
              productId: purchase.productID,
              verificationData: purchase.verificationData.serverVerificationData,
              transactionId: purchase.purchaseID ?? '',
            );

            _purchaseResults.add(
              verification.copyWith(
                status: purchase.status == PurchaseStatus.restored
                    ? PaymentStatus.restored
                    : PaymentStatus.purchased,
              ),
            );

            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            break;
          case PurchaseStatus.error:
            _purchaseResults.add(
              PaymentResult(
                status: PaymentStatus.failed,
                transactionId: purchase.purchaseID ?? '',
                message: purchase.error?.message ?? 'Purchase failed',
              ),
            );
            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            break;
          case PurchaseStatus.canceled:
            _purchaseResults.add(
              PaymentResult(
                status: PaymentStatus.cancelled,
                transactionId: purchase.purchaseID ?? '',
                message: 'Purchase cancelled',
              ),
            );
            if (purchase.pendingCompletePurchase) {
              await _iap.completePurchase(purchase);
            }
            break;
        }
      } catch (e) {
        logger.log('Purchase verification failed', e);
        _purchaseResults.add(
          PaymentResult(
            status: PaymentStatus.failed,
            transactionId: purchase.purchaseID ?? '',
            message: e.toString(),
          ),
        );
      }
    }
  }

  Future<void> dispose() async {
    await _subscription?.cancel();
    await _purchaseResults.close();
  }
}

class PaymentModule {
  final PaymentConfig config;
  late final PaymentLogger logger;
  late final SecurePaymentHttpClient _httpClient;
  late final PaymentGatewayService gatewayService;
  late final WalletBridge walletBridge;
  late final InAppPurchaseService inAppPurchaseService;

  PaymentModule(this.config) {
    logger = PaymentLogger(config.enableLogging);
    _httpClient = SecurePaymentHttpClient(config: config, logger: logger);
    gatewayService = PaymentGatewayService(httpClient: _httpClient, logger: logger);
    walletBridge = WalletBridge(logger);
    inAppPurchaseService = InAppPurchaseService(
      gatewayService: gatewayService,
      logger: logger,
    );
  }

  Future<void> initialize() async {
    await inAppPurchaseService.initialize();
  }

  Future<PurchaseCatalog> loadCatalog() {
    return inAppPurchaseService.queryProducts(config.iapProductIds);
  }

  Future<PaymentResult> payWithWallet(WalletPaymentRequest request) async {
    final available = await walletBridge.isWalletAvailable(request.walletType);
    if (!available) {
      throw PaymentException(
        'wallet_unavailable',
        '${describeEnum(request.walletType)} is not available on this device',
      );
    }

    final walletToken = await walletBridge.presentWallet(request);
    return gatewayService.confirmWalletPayment(
      request: request,
      walletToken: walletToken,
    );
  }

  Future<PaymentResult> tokenizeCard(CardTokenizationRequest request) {
    _assertNoSensitiveLogging();
    return gatewayService.tokenizeCard(request);
  }

  Future<PaymentResult> createPaymentIntent({
    required String orderId,
    required int amountMinor,
    required String currency,
    Map<String, dynamic>? metadata,
  }) {
    return gatewayService.createPaymentIntent(
      orderId: orderId,
      amountMinor: amountMinor,
      currency: currency,
      metadata: metadata,
    );
  }

  Future<PaymentResult> refund({
    required String transactionId,
    required int amountMinor,
    String? reason,
  }) {
    return gatewayService.refund(
      transactionId: transactionId,
      amountMinor: amountMinor,
      reason: reason,
    );
  }

  void _assertNoSensitiveLogging() {
    if (config.enableLogging) {
      logger.log('PCI notice', 'Disable verbose logging in production when handling card data');
    }
  }

  Future<void> dispose() async {
    await inAppPurchaseService.dispose();
    _httpClient.dispose();
  }
}

class PaymentSecurity {
  static void enforceRuntimeChecks() {
    if (kDebugMode) {
      debugPrint('[Payment] Warning: Debug mode is enabled. Disable for release builds.');
    }
  }

  static Map<String, String> secureHeaders({
    required String idempotencyKey,
    String? sessionToken,
  }) {
    return {
      'X-Idempotency-Key': idempotencyKey,
      if (sessionToken != null) HttpHeaders.authorizationHeader: 'Bearer $sessionToken',
    };
  }

  static String generateIdempotencyKey(String seed) {
    final timestamp = DateTime.now().millisecondsSinceEpoch.toString();
    return sha256.convert(utf8.encode('$seed:$timestamp')).toString();
  }
}